-- Cal. Evid. Code §§ 1010-1027 — Psychotherapist-Patient Privilege
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_045', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Evid. Code §§ 1010-1027', 'Evid. Code §§ 1010-1027', 'Psychotherapist-Patient Privilege', 'California statutory privilege protecting confidential communications between patient and psychotherapist from compelled disclosure in legal proceedings.', '["Psychotherapist defined broadly: psychiatrist, psychologist, LCSW, LMFT, and others (§ 1010)","Confidential communication: information transmitted in course of relationship and not intended to be disclosed (§ 1012)","Patient holds the privilege (§ 1014)","Privilege survives death of patient","Exceptions: dangerous patient (Tarasoff), court-ordered examination, child abuse reporting, proceedings to hospitalize patient"]', '[{"section":"1010","description":"Definition of psychotherapist — psychiatrist, psychologist, LCSW, LMFT, etc."},{"section":"1012","description":"Confidential communication defined"},{"section":"1014","description":"Patient privilege — holder may refuse to disclose and prevent others from disclosing"},{"section":"1016","description":"Patient-litigant exception — patient tenders mental condition"},{"section":"1017","description":"Court-appointed psychotherapist exception"},{"section":"1024","description":"Dangerous patient exception (Tarasoff)"},{"section":"1027","description":"Child under 16 victim of crime exception"}]', '["therapy_record","psychiatric_evaluation","forensic_evaluation","privilege_log","motion_to_quash","subpoena"]', '["state-bar-of-california-attorney-conduct-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

-- Cal. Bus. & Prof. Code § 6068 — Duties of Attorneys
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_046', 'ETHICARA', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code § 6068', 'B&P § 6068', 'Duties of Attorneys', 'Comprehensive statutory enumeration of the duties of California attorneys including support of the Constitution, maintenance of respect for courts, honesty, confidentiality, and compliance with court orders.', '["Support Constitution and laws of the United States and California","Maintain respect due to courts and judicial officers","Counsel or maintain only legal actions and defenses","Employ only means consistent with truth","Maintain inviolate confidence and secrets of client (§ 6068(e))","Abstain from offensive personality","Advance no fact prejudicial to honor or reputation of party unless required by justice","Never reject cause of defenseless or oppressed","Comply with court orders and report certain sanctions (§ 6068(o))","Cooperate with State Bar investigations"]', '[{"section":"6068(a)","description":"Support Constitution and laws"},{"section":"6068(b)","description":"Maintain respect for courts"},{"section":"6068(c)","description":"Only legal actions and defenses"},{"section":"6068(d)","description":"Means consistent with truth"},{"section":"6068(e)","description":"Maintain inviolate client confidences and secrets"},{"section":"6068(h)","description":"Never reject cause of defenseless or oppressed"},{"section":"6068(i)","description":"Cooperate and participate in State Bar investigations"},{"section":"6068(o)","description":"Report judicial sanctions to State Bar within 30 days"}]', '["bar_complaint","disciplinary_proceeding","OCTC_investigation","court_order","sanctions_order"]', '["state-bar-of-california-attorney-conduct-audit"]', 'State Bar of California / Supreme Court', 1, 1, datetime('now'), datetime('now'));
